import ast
import operator

def evalInput(inputStr):
    # Define allowed operations
    allowed_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.And: operator.and_,
        ast.Or: operator.or_,
        ast.Not: operator.not_,
    }

    # Safe built-in functions
    safe_functions = {
        'abs': abs,
        'min': min,
        'max': max,
        'sum': sum,
        'len': len,
        'round': round,
        'pow': pow,
        'divmod': divmod,
        'bool': bool,
        'int': int,
        'float': float,
        'str': str,
        'list': list,
        'tuple': tuple,
        'dict': dict,
        'set': set,
        'range': range,
        'enumerate': enumerate,
        'zip': zip,
        'sorted': sorted,
        'reversed': reversed,
        'all': all,
        'any': any,
    }

    def safe_eval(node):
        if isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.Name):
            if node.id in ['True', 'False', 'None']:
                return {'True': True, 'False': False, 'None': None}[node.id]
            else:
                raise ValueError(f"Undefined variable: {node.id}")
        elif isinstance(node, ast.BinOp):
            if type(node.op) in allowed_ops:
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                return allowed_ops[type(node.op)](left, right)
            else:
                raise ValueError(f"Unsupported operation: {type(node.op)}")
        elif isinstance(node, ast.UnaryOp):
            if type(node.op) in allowed_ops:
                operand = safe_eval(node.operand)
                return allowed_ops[type(node.op)](operand)
            else:
                raise ValueError(f"Unsupported unary operation: {type(node.op)}")
        elif isinstance(node, ast.Compare):
            left = safe_eval(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                if type(op) in allowed_ops:
                    right = safe_eval(comparator)
                    result = allowed_ops[type(op)](left, right)
                    if not result:
                        return False
                    left = right
                else:
                    raise ValueError(f"Unsupported comparison: {type(op)}")
            return True
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id in safe_functions:
                args = [safe_eval(arg) for arg in node.args]
                return safe_functions[node.func.id](*args)
            else:
                raise ValueError(f"Unsupported function call")
        elif isinstance(node, ast.List):
            return [safe_eval(elem) for elem in node.elts]
        elif isinstance(node, ast.Tuple):
            return tuple(safe_eval(elem) for elem in node.elts)
        elif isinstance(node, ast.Dict):
            return {safe_eval(k): safe_eval(v) for k, v in zip(node.keys, node.values)}
        elif isinstance(node, ast.Set):
            return {safe_eval(elem) for elem in node.elts}
        else:
            raise ValueError(f"Unsupported node type: {type(node)}")

    try:
        tree = ast.parse(inputStr, mode='eval')
        return safe_eval(tree.body)
    except Exception as e:
        raise ValueError(f"Invalid expression: {str(e)}")

